GENERAL_FAQ = [
    {"q": "What services does AHA Technologies offer?", "sub": "Company Overview", "sa": "AHA Technologies provides Level-4 component-level PCB repair, home theatre design and installation, Hi-Fi audio system integration, and commercial audio solutions in Bangalore.", "a": "AHA Technologies is a specialist AV engineering laboratory based in Bangalore, India. Our core services include: (1) Level-4 component-level PCB and amplifier repair for high-end AV receivers, integrated amplifiers, and power amplifiers. (2) Home theatre design and Dolby Atmos installation for residential and dedicated cinema rooms. (3) Hi-Fi stereo system design, source integration, and acoustic optimisation. (4) Commercial audio system design for conference rooms, restaurants, hotels, and retail environments. (5) Calibration services using Audyssey, Dirac Live, YPAO, and MCACC. We are an engineering-first lab, not a retail showroom. We do not sell new equipment but we can source components and recommend trusted suppliers.", "k": "aha technologies, services, what do you do, repair, installation, bangalore, av", "syn": "What does AHA Technologies do?, What services do you provide?, What can you fix?, What do you specialize in?", "rel": "What is Level 4 PCB repair?, Do you repair AV receivers?, Do you install home theatres?"},
    {"q": "Where is AHA Technologies located?", "sub": "Company Overview", "sa": "AHA Technologies is based in Bangalore, Karnataka, India. Contact us for the current service centre address and operating hours.", "a": "AHA Technologies operates a specialist AV engineering laboratory in Bangalore, Karnataka. We serve clients across Bangalore directly, and we also accept equipment sent via courier from other cities across India. For customers located outside Bangalore, we recommend securely packaging equipment in rigid foam-lined cartons, not bubble wrap, to prevent transit damage. Valuable or fragile units should be insured before shipping. Contact us via WhatsApp or email to confirm the current lab address before shipping. We do not have retail walk-in availability without a prior appointment. All diagnostic and repair work is completed at our Bangalore facility.", "k": "location, address, where are you, bangalore, karnataka, service centre", "syn": "Where are you based?, What is your address?, Can I visit your shop?, Where can I drop off my amplifier?", "rel": "How long does a repair take?, Can I courier my equipment?"},
    {"q": "How do I book a service appointment with AHA Technologies?", "sub": "Booking Process", "sa": "You can book a service appointment via WhatsApp, email, or through the booking form on our website. Describe your equipment model and the fault observed.", "a": "To book a service appointment with AHA Technologies, use any of the following methods: (1) WhatsApp: Send a message to our service number describing your equipment brand, model, and the fault symptom. Include a photograph of the unit and of any visible damage if available. (2) Website Lead Form: Fill in the service request form on our website. Include your contact details and a brief description of the fault. (3) Email: Send your unit details and fault description to our service email. Once we receive your request, our team will confirm the appointment slot and provide the drop-off address. Please do not drop off equipment without prior confirmation.", "k": "book appointment, schedule, service booking, how to book, drop off", "syn": "How do I request a service?, How to book repair?, How to schedule a diagnostic?", "rel": "Where is AHA Technologies located?, How long does a repair take?"},
    {"q": "How long does a repair take at AHA Technologies?", "sub": "Repair Process", "sa": "Standard Level-4 diagnostics take 24 to 48 hours. Total repair time depends on component availability and fault complexity, typically ranging from 3 to 10 working days.", "a": "Our standard bench diagnostic takes 24 to 48 hours for a qualified engineer to fully assess the fault. The total repair time depends on: (1) Fault complexity — straightforward capacitor replacements or output transistor failures on common models are typically completed in 3 to 5 working days. (2) Component availability — rare or obsolete components may need to be imported, typically adding 5 to 14 days. (3) Queue status — we do not rush repairs. All units undergo extensive thermal burn-in testing post-repair before return. We do not provide same-day or next-day repair guarantees for complex electronics. We will keep you informed throughout the process and notify you before proceeding with any repair if the cost estimate changes.", "k": "repair time, how long, turnaround, when ready, duration, timeline", "syn": "How long will my repair take?, When will my amplifier be ready?, What is the turnaround time?", "rel": "What is Level 4 PCB repair?, Do you charge a diagnostic fee?"},
    {"q": "Do you charge a diagnostic fee?", "sub": "Pricing", "sa": "Yes, AHA Technologies charges a standard bench diagnostic fee. This fee is adjusted against your final repair bill if you proceed with the repair.", "a": "AHA Technologies charges a standard bench diagnostic fee for all equipment submitted for assessment. This fee reflects the time our senior engineers spend using precision test equipment — including oscilloscopes, thermal cameras, ESR meters, and function generators — to accurately diagnose the root cause of the fault. The diagnostic fee is NOT a guessing exercise. It covers a thorough technical assessment. If you choose to proceed with the repair, the bench fee is deducted from the final repair bill. If you choose not to proceed after receiving the diagnosis, the bench fee is retained to cover the engineer's time. Diagnostic fees vary by equipment type and complexity. Contact us for current pricing.", "k": "diagnostic fee, bench fee, checking charge, inspection cost, free check", "syn": "Is there a fee to check my amplifier?, Do you charge for diagnosis?, Is the inspection free?", "rel": "How long does a repair take?, How do I book a repair?"},
    {"q": "Do you repair imported or grey market equipment?", "sub": "Repair Policy", "sa": "Yes. AHA Technologies repairs imported, out-of-warranty, and grey market AV equipment. We do not require official service authorisation.", "a": "AHA Technologies regularly repairs equipment purchased abroad, imported units, grey market products, and equipment whose brand service centres have refused to work on due to warranty expiry or import status. As an independent engineering laboratory, we are not bound by brand authorisation requirements. We repair equipment at the component level, meaning we do not necessarily require official spare parts from the manufacturer — we source equivalent or superior components from qualified distributors. However, certain proprietary firmware chips and brand-specific digital signal processors may not be replicable, and we will advise you honestly if a particular fault cannot be resolved without an official OEM part.", "k": "grey market, imported, warranty void, out of warranty, foreign purchase, bought abroad", "syn": "Can you repair equipment bought overseas?, Will you fix a unit not under warranty?, Do you repair parallel imports?", "rel": "What is Level 4 PCB repair?, What brands do you repair?"},
    {"q": "What brands of AV equipment do you repair?", "sub": "Supported Brands", "sa": "We repair all major AV brands including Denon, Yamaha, Marantz, NAD, Harman Kardon, Pioneer, Onkyo, Sony, Cambridge Audio, and many others.", "a": "AHA Technologies repairs a wide range of AV equipment brands. Our work is not brand-restricted — if it has electronic components, we can diagnose it. Commonly repaired brands include: Denon, Yamaha, Marantz, NAD, Onkyo, Pioneer, Sony, Harman Kardon, Anthem, Cambridge Audio, Arcam, Rotel, McIntosh, Luxman, Accuphase, B&W (Bowers & Wilkins) active speakers, KEF LSX series, and many more. We also repair vintage equipment from brands such as Technics, Sansui, Kenwood, Pioneer, and Luxman. Equipment age is not a barrier for us — older units with common component types are often more straightforward to repair than modern proprietary DSP-heavy systems.", "k": "brands, denon, yamaha, marantz, nad, pioneer, sony, onkyo, cambridge audio, supported brands", "syn": "What amplifiers do you repair?, Which AV receivers can you fix?, Do you repair Denon?, Do you fix Yamaha?", "rel": "Do you repair imported equipment?, What is Level 4 PCB repair?"},
    {"q": "Can I courier my AV equipment to AHA Technologies?", "sub": "Logistics", "sa": "Yes. Out-of-city customers can courier equipment to our Bangalore lab. Securely pack units in rigid foam, not bubble wrap, and insure the shipment.", "a": "AHA Technologies accepts equipment shipped via courier from customers outside Bangalore. Before shipping, please: (1) Contact us via WhatsApp or email to confirm the correct current lab address. (2) Pack the unit in its original carton if available. If not, use 50mm rigid foam on all six sides inside a sturdy outer carton. Do NOT use bubble wrap or foam peanuts alone — these provide inadequate protection for heavy amplifiers. (3) Insure the shipment for the full replacement value of the equipment. (4) Write 'FRAGILE ELECTRONIC EQUIPMENT' on all sides of the outer carton. (5) Send us the tracking number. We are not responsible for transit damage caused by insufficient packaging. Upon receipt, we will inspect the unit and confirm receipt via WhatsApp.", "k": "courier, shipping, mail, parcel, send equipment, out of city", "syn": "Can I ship my amplifier to you?, Can I send my AV receiver by courier?, Do you accept posted equipment?", "rel": "Where is AHA Technologies located?, How do I book a service?"},
    {"q": "What is the warranty on your repairs?", "sub": "Warranty Policy", "sa": "AHA Technologies provides a warranty on all completed repairs. The warranty period varies by repair type. Contact us for specific warranty terms.", "a": "All repairs completed by AHA Technologies carry a repair warranty covering the specific fault that was diagnosed and repaired. The warranty covers the identical fault recurring due to the repair work or components used. It does not cover: (1) New, unrelated faults that develop after the repair. (2) Damage caused by power surges, improper handling, or physical impact after the unit is returned. (3) Secondary faults caused by the original failure that were not identified during the initial diagnostic (for example, if a shorted output transistor has damaged a driver stage that is not immediately apparent until the unit is tested under load). We will always advise you at the time of quotation if there are secondary components at risk. Warranty terms vary by repair type. Please discuss this with our service team before proceeding.", "k": "warranty, guarantee, repair warranty, after service warranty, defect warranty", "syn": "Is there a warranty on my repair?, What happens if it breaks again?, Do you guarantee your repairs?", "rel": "Do you charge a diagnostic fee?, How long does a repair take?"},
    {"q": "Do you offer on-site technician visits?", "sub": "Site Visits", "sa": "Yes. AHA Technologies provides site visits for home theatre installation, room calibration, AV system configuration, and wiring diagnosis within Bangalore.", "a": "AHA Technologies offers on-site technician visits for residential and commercial clients within Bangalore and the surrounding area. Site visits are appropriate for: (1) Home theatre installation and speaker placement. (2) AV receiver configuration and calibration. (3) Wiring and rack infrastructure assessment. (4) Acoustic measurement and room correction tuning. (5) Commercial audio system commissioning and fault diagnosis. Component-level PCB soldering and repair work must be performed at our laboratory — we do not carry full bench equipment on-site. Site visit fees apply and vary by location and scope. Contact us to discuss your requirements and schedule a visit.", "k": "site visit, home visit, on-site, technician, installation visit, come to my house", "syn": "Can you come to my home?, Do you visit for installation?, Can a technician visit?", "rel": "Do you install home theatres?, What calibration services do you offer?"},
    {"q": "Do you buy or sell used AV equipment?", "sub": "Company Policy", "sa": "No. AHA Technologies is an engineering repair and installation laboratory. We do not buy, sell, or trade used AV equipment.", "a": "AHA Technologies is exclusively an AV engineering repair, installation, and calibration specialist. We are not a retail shop or a second-hand AV equipment dealer. We do not buy equipment from customers, we do not sell used units, and we do not facilitate equipment trades or exchanges. If you are looking to sell or acquire used AV equipment, we recommend specialist hi-fi forums, second-hand platforms, or contacting dedicated AV resellers. We are happy to provide a technical inspection of a unit you are considering purchasing to verify its condition before you buy. Contact us to arrange a pre-purchase inspection.", "k": "buy sell, second hand, trade, exchange, used equipment, second hand gear", "syn": "Do you sell amplifiers?, Can I sell my AV receiver to you?, Do you deal in second-hand gear?", "rel": "What services does AHA Technologies offer?, What brands do you repair?"},
    {"q": "Do you repair car audio systems?", "sub": "Out of Scope", "sa": "No. AHA Technologies specialises exclusively in home and commercial AV systems. We do not service or install 12-volt car audio systems.", "a": "AHA Technologies is a specialist in home and commercial audio-visual engineering. Our expertise covers home theatre, Hi-Fi, and architectural audio systems. We do not service, repair, or install 12-volt automotive audio systems, including car head units, car amplifiers, car subwoofers, or vehicle wiring looms. Our diagnostic and soldering equipment is configured for mains-powered domestic and commercial electronics. For car audio servicing, we recommend contacting a specialist car audio retailer or a vehicle AV customisation workshop. We also do not cover motorcycle or vehicle entertainment system installations.", "k": "car audio, car stereo, 12v, vehicle audio, automotive, car amplifier", "syn": "Can you fix my car stereo?, Do you install car audio?, Car amp repair?", "rel": "What brands do you repair?, What services does AHA Technologies offer?"},
    {"q": "Do you repair televisions or TV screens?", "sub": "Out of Scope", "sa": "No. AHA Technologies does not repair television sets, display panels, or broken screens. We specialise in audio electronics only.", "a": "AHA Technologies is an audio-first engineering laboratory. Our core competency is in audio electronics: AV receivers, amplifiers, DACs, speakers, and related signal processing equipment. We do not repair: Television sets (LCD, OLED, QLED, plasma), LED display panels, broken or cracked screens, TV remote controls, or smart TV software and firmware issues. For television panel repair or screen replacement, please contact the brand's authorised service centre directly. We do observe that many AV receivers contain HDMI switching boards and video processing stages which we can and do repair — this is distinct from repairing flat panel display hardware.", "k": "tv repair, television, samsung tv, lg tv, broken screen, panel replacement, oled", "syn": "Can you fix my TV?, Do you do TV screen repair?, TV panel repair?", "rel": "Do you repair HDMI boards?, What brands do you repair?"},
    {"q": "Do you repair headphones or earphones?", "sub": "Out of Scope", "sa": "No. AHA Technologies focuses on macro audio electronics. We do not repair consumer headphones, earphones, or AirPods.", "a": "AHA Technologies specialises in macro-audio electronics: amplifiers, AV receivers, speaker systems, and professional audio equipment. Our facility is equipped for through-hole and SMD PCB repair, BGA rework, and high-current power electronics. We do not perform micro-soldering repairs on consumer personal audio devices such as: Headphones (dynamic, planar, electrostatic), earphones or in-ear monitors, AirPods or wireless earbuds, or portable audio players. These devices require different tooling — notably microscope-assisted micro-soldering and specialised flexible PCB handling — which is outside our current service scope. For headphone repair, we recommend contacting the manufacturer or specialist personal audio technicians.", "k": "headphones, earphones, airpods, earbuds, iem, portable audio, headphone repair", "syn": "Can you fix my headphones?, Do you repair AirPods?, Earphone repair?", "rel": "What services does AHA Technologies offer?"},
    {"q": "What is an AV receiver?", "sub": "Definitions", "sa": "An AV receiver (AVR) is the central hub of a home theatre system. It decodes audio formats, powers speaker channels, switches HDMI and digital inputs, and applies room correction processing.", "a": "An Audio-Visual Receiver (AVR) is the nerve centre of a home theatre system. It performs several critical functions simultaneously: (1) Audio decoding — it receives digital audio bitstreams from Blu-ray players, streaming devices, and gaming consoles and decodes proprietary formats such as Dolby TrueHD, Dolby Atmos, DTS:X, and Auro-3D into individual channel signals. (2) Amplification — it powers each speaker channel using built-in class AB or class D amplifiers, typically delivering between 80W and 180W per channel. (3) HDMI switching — it routes video signals from multiple HDMI sources to TV or projector, passing through 4K HDR or 8K content. (4) Room correction — modern receivers include Audyssey, YPAO, or Dirac Live DSP to correct room acoustic anomalies. Leading brands include Denon, Yamaha, Marantz, and Onkyo.", "k": "av receiver, avr, what is receiver, home theatre hub, denon, yamaha, marantz", "syn": "What is an AVR?, What is a surround sound receiver?, What does an AV receiver do?", "rel": "What is Dolby Atmos?, What is HDMI ARC?, How do I calibrate my AV receiver?"},
    {"q": "What is the difference between an AV receiver and an amplifier?", "sub": "Definitions", "sa": "An AV receiver combines a multi-channel amplifier, audio/video decoder, HDMI switching, and room correction in one unit. A standalone amplifier focuses only on amplification without decoding or switching.", "a": "An AV receiver is a multi-function unit that integrates: HDMI switching and video processing, Dolby/DTS audio decoding, multi-channel amplification (5 to 13 channels typically), and room correction DSP. A stereo integrated amplifier focuses exclusively on amplifying an audio signal from a pre-selected source without decoding or HDMI. A power amplifier provides only amplification and has no source selection or decoding capability. In home theatre, an AV receiver is the standard all-in-one solution. In high-performance Hi-Fi, separating the preamplifier, DAC, and power amplifier is preferred for reduced noise floor and superior channel isolation. Audiophiles often use a dedicated processor (pre/pro) upstream of separate power amplifiers to extract more performance.", "k": "av receiver vs amplifier, difference, what is amplifier, integrated amplifier, power amp", "syn": "Receiver vs amplifier difference?, Is an AVR the same as an amplifier?", "rel": "What is a stereo amplifier?, What is an integrated amplifier?"},
    {"q": "What is impedance in speakers?", "sub": "Technical Concepts", "sa": "Speaker impedance is the total opposition to alternating current, measured in ohms. Most home speakers are rated at 4, 6, or 8 ohms. Lower impedance demands more current from the amplifier.", "a": "Speaker impedance is the frequency-dependent resistance that a speaker presents to the amplifier driving it. It is measured in ohms (Ω) and represents the total opposition — combining resistive, inductive, and capacitive elements — to the alternating current signal from the amplifier. Common speaker impedance ratings are 4Ω, 6Ω, and 8Ω. A lower impedance load demands more current from the amplifier. An amplifier rated for 8Ω loads may overheat or trigger protection mode when driving a 4Ω speaker, particularly at high volumes, because the current demand doubles. Always verify that your amplifier is rated to drive the impedance of your chosen speakers. Most modern AV receivers specify a minimum speaker impedance of 6Ω, while some high-current designs support 4Ω loads.", "k": "impedance, ohm, 4 ohm, 8 ohm, speaker load, amplifier drive", "syn": "What ohm speaker should I use?, What does impedance mean?, 4 ohm vs 8 ohm speakers", "rel": "What causes an amplifier to overheat?, What is speaker sensitivity?"},
    {"q": "What is speaker sensitivity?", "sub": "Technical Concepts", "sa": "Speaker sensitivity is measured in dB (SPL) per 1 watt at 1 metre distance. A higher sensitivity rating means louder output for the same amplifier power.", "a": "Speaker sensitivity is a measurement of how efficiently a speaker converts electrical power into acoustic output. It is expressed as dB SPL (sound pressure level) measured at 1 metre distance, driven by 1 watt (or 2.83 volts into 8 ohms). A speaker with a sensitivity of 90dB/1W/1m produces 90dB SPL at 1 metre using 1 watt. A speaker rated at 83dB/1W/1m requires roughly 5 times more power to achieve the same volume. High-sensitivity speakers (90dB and above) are ideal when paired with lower-power amplifiers, such as valve/tube amplifiers producing 10 to 30 watts. Low-sensitivity speakers (83 to 87dB) require more amplifier headroom but often achieve superior bass extension. Sensitivity and impedance together determine how demanding a speaker is of its amplifier.", "k": "sensitivity, db/w/m, speaker efficiency, 1 watt 1 metre, dB SPL", "syn": "What is dB/W/m?, How sensitive are my speakers?, Speaker efficiency explained", "rel": "What is impedance?, How much power do I need for my speakers?"},
    {"q": "What is signal-to-noise ratio in audio?", "sub": "Technical Concepts", "sa": "Signal-to-noise ratio (SNR) measures the difference in decibels between the desired audio signal and the background noise floor. Higher SNR values indicate quieter, cleaner audio.", "a": "Signal-to-noise ratio (SNR or S/N ratio) is a measurement of the ratio between the useful audio signal level and the background noise produced by an electronic component. It is expressed in decibels (dB). An SNR of 110dB means the signal is 110dB louder than the noise floor — this is considered excellent in consumer electronics. Consumer AV receivers typically achieve 90–105dB SNR. High-end Hi-Fi equipment may exceed 110dB. A low SNR manifests as audible hiss, hum, or noise at low listening levels, particularly noticeable with sensitive speakers in a quiet room. SNR degrades in ageing equipment due to failed filter capacitors in the power supply, degraded op-amps, or contaminated volume potentiometers. Improving SNR requires targeted component replacement and careful PCB layout during repair.", "k": "signal to noise ratio, snr, noise floor, hiss, quiet amplifier, clean audio", "syn": "What is S/N ratio?, What does 105dB SNR mean?, Why does my amplifier hiss?", "rel": "Why does my amplifier produce hiss?, What is total harmonic distortion?"},
    {"q": "What is total harmonic distortion (THD) in audio?", "sub": "Technical Concepts", "sa": "Total harmonic distortion (THD) measures the percentage of unwanted harmonic frequencies added to an audio signal by an amplifier or processor. Lower THD means cleaner sound.", "a": "When an amplifier processes an audio signal, it ideally outputs exactly what it receives — amplified proportionally. In practice, non-linearities in transistors, op-amps, and passive components cause the amplifier to add harmonic frequencies that were not present in the original signal. These spurious harmonics are what we call distortion. Total Harmonic Distortion is expressed as a percentage (%) or in dB. A THD of 0.01% means 1 part in 10,000 of the signal is distortion, which is inaudible to most listeners. A THD of 1% or higher is typically audible and unpleasant. THD measurements are often quoted at rated output power into a specific impedance load (e.g. THD+N < 0.05% at 100W into 8Ω). In repair contexts, rising THD indicates failing output transistors, bias drift, or feedback loop issues.", "k": "THD, total harmonic distortion, distortion percentage, clean amplifier, audio clarity", "syn": "What is THD in amplifiers?, What causes distortion?, Why is my audio distorted?", "rel": "What causes amplifier distortion?, What is SNR?"},
    {"q": "What is RMS power in audio?", "sub": "Technical Concepts", "sa": "RMS power is the continuous, sustained power an amplifier can deliver, measured in watts. It is the most meaningful power specification for comparing amplifiers.", "a": "RMS (Root Mean Square) power is the mathematically derived continuous power rating of an amplifier — the amount of power it can sustain indefinitely into a specified load without distortion or thermal shutdown. It is the standard measurement used to compare amplifiers fairly. RMS power is measured under specific conditions: typically at a defined frequency (often 1kHz), a specified load impedance (commonly 8Ω), and a THD limit (often 0.08% or 1%). Peak power ratings, PMPO (Peak Music Power Output) ratings, and other marketing terms represent instantaneous burst capability and are not useful for real-world comparisons. Always compare amplifiers using rated RMS power at 8Ω, measured with all channels simultaneously driven. A receiver rated at 100W RMS per channel into 8Ω under these conditions is significantly more powerful than one rated at 100W with only one channel driven.", "k": "RMS power, watts, continuous power, PMPO, amplifier power rating, how powerful", "syn": "What is RMS wattage?, What does 100W mean?, PMPO vs RMS explained", "rel": "What is THD?, How much power do I need for my speakers?"},
    {"q": "What is the difference between active and passive speakers?", "sub": "Definitions", "sa": "Passive speakers require an external amplifier to drive them. Active speakers have a built-in amplifier and connect directly to a signal source or preamplifier output.", "a": "Passive speakers contain no internal amplification. They receive amplified signals directly from an external power amplifier or AV receiver output. The crossover network inside a passive speaker divides the amplified signal into frequency bands for the tweeter, midrange, and woofer drivers. Passive systems offer flexibility — you can upgrade the amplifier independently. Active speakers integrate one or more power amplifiers inside the speaker cabinet. The crossover typically operates at line level before amplification, allowing each driver to have its own dedicated amplifier stage — this is called bi-amping or tri-amping internally. Active systems offer superior driver-amplifier matching and reduced intermodulation distortion. Examples: KEF LSX, Genelec, ADAM Audio. The trade-off is reduced repair simplicity and higher purchase cost. Professional studio monitors are almost universally active.", "k": "active passive speaker, powered speaker, built in amplifier, speaker with amp, difference", "syn": "What is a powered speaker?, Active vs passive speakers explained?, Do speakers need an amplifier?", "rel": "What is an integrated amplifier?, What are crossover networks?"},
    {"q": "What is HDMI ARC?", "sub": "Connectivity", "sa": "HDMI ARC (Audio Return Channel) allows audio to travel from your TV back to your AV receiver or soundbar through the same HDMI cable, eliminating a separate optical cable.", "a": "HDMI ARC (Audio Return Channel) is a feature introduced in HDMI 1.4 that allows a single HDMI connection to carry audio in both directions between a TV and an AV receiver or soundbar. Without ARC, you need to run a separate optical (TOSLINK) or coaxial cable to send TV audio to your sound system. With ARC, the HDMI cable that carries video to your TV can simultaneously carry audio back from the TV's built-in tuner, apps, or streaming services to the AV receiver. HDMI ARC supports PCM stereo, Dolby Digital 5.1, and DTS 5.1. It does not reliably support lossless formats like Dolby TrueHD or DTS-HD Master Audio — those require eARC. Many ARC-related faults are caused by HDMI handshake failures, CEC compatibility conflicts, or failing HDMI switch ICs on the AVR's HDMI board.", "k": "ARC, hdmi arc, audio return channel, tv to receiver, optical cable alternative", "syn": "What is ARC on HDMI?, How does audio return channel work?, TV to AVR audio via HDMI", "rel": "What is eARC?, What is HDMI CEC?, How do I fix HDMI ARC problems?"},
    {"q": "What is HDMI eARC?", "sub": "Connectivity", "sa": "HDMI eARC (Enhanced Audio Return Channel) is an HDMI 2.1 feature that supports full lossless audio formats including Dolby TrueHD, Dolby Atmos, and DTS:X via a single HDMI cable.", "a": "eARC (Enhanced Audio Return Channel) is introduced with HDMI 2.1 and significantly expands upon the original ARC specification. Where ARC is limited to PCM stereo and lossy surround formats, eARC supports: Dolby TrueHD, Dolby Atmos, DTS-HD Master Audio, DTS:X, and uncompressed multi-channel PCM audio at up to 192kHz, 24-bit. eARC also uses an Ethernet channel for higher bandwidth, achieving up to 37Mbps compared to ARC's 1Mbps. For eARC to function, both the TV and the AV receiver (or soundbar) must have HDMI 2.1 eARC-compatible ports, and a Certified HDMI 2.1 cable must be used. Many eARC issues arise from using older HDMI cables that cannot carry the bandwidth, or from firmware incompatibilities between TV and receiver brands.", "k": "eARC, enhanced audio return channel, hdmi 2.1, dolby atmos eARC, lossless audio TV", "syn": "What is eARC?, eARC vs ARC explained, TrueHD via HDMI TV?", "rel": "What is HDMI ARC?, What is Dolby Atmos?, HDMI board repair"},
    {"q": "What is HDCP and why does it cause problems?", "sub": "Connectivity", "sa": "HDCP (High-bandwidth Digital Content Protection) is a copy-protection protocol embedded in HDMI. Incompatibilities between devices cause no-picture outputs or flickering screens.", "a": "HDCP (High-bandwidth Digital Content Protection) is a copy-protection standard implemented on HDMI connections between source devices, AV receivers, and displays. Every HDMI device performs an encrypted 'handshake' to verify that all connected devices are authorised to receive and display the content. Problems arise when: (1) An older device does not support a newer HDCP version (e.g. HDCP 2.2 required for 4K Blu-ray, HDCP 2.3 for certain streaming services). (2) The HDMI switch IC on the AV receiver's board suffers a firmware or hardware fault causing handshake failures. (3) Incompatible firmware between TV and AVR brands causes negotiation timeouts. Symptoms include: black screen, no picture, flickering screen followed by loss of image, or an on-screen message stating 'HDMI cannot be displayed.' HDCP-related faults on the AV receiver HDMI board are repairable in many cases by replacing the HDMI switch IC.", "k": "HDCP, copy protection, no picture, black screen, HDMI protection, handshake failure", "syn": "Why does my TV show no picture via HDMI?, HDCP error explained, HDMI copy protection", "rel": "What is HDMI ARC?, Do you repair HDMI boards?, HDMI handshake problems"},
    {"q": "What is Dolby Digital?", "sub": "Audio Formats", "sa": "Dolby Digital is a lossy audio codec that delivers 5.1 surround sound at up to 448kbps. It is the standard surround audio format for DVDs and standard Blu-rays.", "a": "Dolby Digital (also called AC-3) is a lossy audio compression codec developed by Dolby Laboratories. It delivers up to 5.1 channels of discrete surround sound and is the standard audio format used on standard DVD, broadcast television, and many streaming platforms. Dolby Digital supports bit rates up to 448kbps on consumer media and 640kbps in some cinema applications. As a lossy format, some audio data is discarded during encoding to reduce file size, which means it does not capture every nuance of the original studio recording. Dolby Digital Plus (DD+) is an improved version with higher bit rates and additional channels. Dolby TrueHD is the lossless version used on Blu-ray, offering studio-master quality without data loss. Most AV receivers support all three Dolby formats.", "k": "dolby digital, AC-3, 5.1 surround, dvd audio, dd plus, dolby codec", "syn": "What is Dolby Digital 5.1?, Dolby audio explained, What format is DVD audio?", "rel": "What is DTS?, What is Dolby TrueHD?, What is Dolby Atmos?"},
    {"q": "What is DTS:X?", "sub": "Audio Formats", "sa": "DTS:X is DTS's object-based surround sound format, competing directly with Dolby Atmos. It delivers audio objects that can be placed anywhere in three-dimensional space.", "a": "DTS:X is an object-based audio format developed by DTS as their competitor to Dolby Atmos. Like Atmos, DTS:X places individual sounds as audio objects in three-dimensional space rather than assigning them to fixed channel positions. DTS:X can render audio through any speaker configuration without requiring specific speaker counts — it adapts its output to whatever speakers are connected. DTS:X content is found on Blu-ray discs and some streaming platforms. DTS:X Pro extends support to up to 32 speaker positions for professional and dedicated cinema room installations. Unlike Dolby Atmos, DTS:X does not specify a unique in-ceiling or upfiring speaker position — it is more flexible in this regard. Compatability: Most modern AV receivers that support Dolby Atmos also support DTS:X. Check the HDMI board firmware for DTS:X decoder availability.", "k": "DTS:X, DTS X, object audio, surround format, dts vs dolby atmos, DTSx", "syn": "What is DTS X?, DTS:X explained, Is DTS:X the same as Atmos?", "rel": "What is Dolby Atmos?, What is DTS-HD Master Audio?, Which AV receivers support DTS:X?"},
    {"q": "What is the difference between Dolby Atmos and DTS:X?", "sub": "Format Comparison", "sa": "Both are object-based 3D surround formats. Dolby Atmos requires specific height speaker positions while DTS:X is more flexible. Content availability differs between platforms.", "a": "Dolby Atmos and DTS:X are both object-based immersive audio formats. Key differences: (1) Speaker specification: Dolby Atmos defines specific height speaker positions and configurations (e.g. 5.1.2, 7.1.4). DTS:X is more adaptable and can work with any speaker layout. (2) Content availability: Dolby Atmos has significantly broader support — Netflix, Disney+, Apple TV+, Blu-ray, and many streaming platforms. DTS:X is primarily found on physical Blu-ray discs. (3) Height rendering: Dolby Atmos restricts overhead audio objects to defined height speaker positions. DTS:X renders overhead content to whatever height speakers are available, even creating perceived overhead effects without dedicated height speakers through DTS Virtual:X. (4) Receiver compatibility: Most modern AV receivers support both. Marantz and Denon typically provide excellent Dolby Atmos performance; Yamaha CINEMA DSP extends both formats generously.", "k": "atmos vs dts x, dolby vs dts, difference, 3d audio, object audio comparison", "syn": "Dolby Atmos or DTS:X which is better?, Atmos vs DTS:X comparison", "rel": "What is Dolby Atmos?, What is DTS:X?, Height speakers for home theatre"},
    {"q": "What is Auro-3D?", "sub": "Audio Formats", "sa": "Auro-3D is a channel-based immersive audio format from Barco that adds height layers to standard surround sound. It is found on Blu-ray and select streaming content.", "a": "Auro-3D is an immersive audio format developed by Auro Technologies, a Belgian company originally focused on cinema. Unlike Dolby Atmos and DTS:X — which are object-based — Auro-3D is a layer-based format. It adds additional speaker layers above the standard surround plane: a Voice of God speaker at the top, a height layer, and a front height layer. Auro-3D's base configuration is 9.1 (5.1 + 4 height channels). It is backward compatible with standard 5.1 and 7.1 hardware. Auro-3D content is encoded on some Blu-ray discs and in premium cinema installations. Support among mainstream AV receivers is limited compared to Dolby Atmos and DTS:X, though Marantz offers Auro-3D decoding in some of their higher-end models. It is more common in professional cinema contexts than in home theatre installations.", "k": "auro 3d, auro technologies, height audio, barco, immersive audio, cinema audio", "syn": "What is Auro-3D sound?, Auro 3D vs Dolby Atmos, Layer-based surround audio", "rel": "What is Dolby Atmos?, What is DTS:X?, What is a 9.1.4 system?"},
    {"q": "What is the role of a centre channel speaker in home theatre?", "sub": "Speaker Roles", "sa": "The centre channel speaker anchors dialogue directly in front of the listener, ensuring voices sound like they originate from the screen regardless of where the viewer sits.", "a": "In a home theatre system, the centre channel speaker is often cited as the most critical speaker in the array. It carries approximately 60 to 70 percent of the total audio information in a typical film mix — primarily dialogue, on-screen effects, and music that is sonically tied to the centre of the visual field. The centre channel ensures that dialogue sounds as though it is originating from the characters on screen rather than from the left or right speakers. Without a dedicated centre channel, dialogue would be phantomed between the left and right speakers — an effect that works passably for listening from the absolute centre position but degrades significantly for off-axis seating. The centre speaker should be positioned as close to the screen as possible, ideally centred and at ear height, or aligned with the tweeter axis of the left and right speakers.", "k": "centre channel, center speaker, dialogue, home theatre, role of center", "syn": "What does the center speaker do?, Why do I need a centre channel?, Centre speaker explained", "rel": "What is a 5.1 system?, Speaker placement home theatre, What is a home theatre calibration?"},
    {"q": "What does a subwoofer do in a home theatre system?", "sub": "Speaker Roles", "sa": "A subwoofer reproduces very low bass frequencies (typically 20Hz to 80Hz or 120Hz) that floor-standing and bookshelf speakers cannot accurately produce on their own.", "a": "A subwoofer is a specialised speaker driver and enclosure designed to reproduce very low-frequency bass content, typically between 20Hz and 80–120Hz depending on the AV receiver's crossover settings. Bass frequencies at this range require significant cone excursion — the cone must move large distances — which a small tweeter or midrange driver cannot physically achieve. By off-loading bass reproduction to a dedicated subwoofer, the full-range speakers (including tower and bookshelf models) are relieved of their most power-hungry task, allowing them to play cleaner and louder in their optimal range. A properly calibrated subwoofer integrates seamlessly with the main speakers — the bass transition is inaudible and the bass appears to come from the front of the room. Subwoofer placement, crossover frequency, and phase alignment are critical to achieving a non-boomy, accurate bass response.", "k": "subwoofer, LFE, bass, low frequency, crossover, 80Hz, subwoofer role", "syn": "Why do I need a subwoofer?, What does a sub do?, Low frequency speaker", "rel": "What is a 5.1 system?, Where to place a subwoofer?, What is an LFE channel?"},
    {"q": "What is the LFE channel?", "sub": "Technical Concepts", "sa": "LFE (Low Frequency Effects) is the dedicated .1 channel in surround formats like 5.1 and 7.1. It carries discrete low-frequency audio content specifically mixed for the subwoofer.", "a": "The LFE (Low Frequency Effects) channel is the dedicated bass channel in multichannel audio formats. In a 5.1 system, the '.1' refers to this channel. The LFE channel carries discrete bass content specifically mixed by sound designers to be reproduced by the subwoofer — explosions, earthquake rumbles, cinematic impacts, and sub-bass music. The LFE channel is band-limited — it typically contains audio content only up to 120Hz. It is distinct from the bass management redirected to the subwoofer from 'small' speakers (which is redirected via the AV receiver's crossover, not via the LFE path). Confusing LFE and bass management is a common misconfiguration issue. Both paths feed the subwoofer, but independently. If a subwoofer has no LFE output, check the AV receiver's subwoofer output assignment and bass management settings.", "k": "LFE, .1 channel, low frequency effects, subwoofer channel, bass channel", "syn": "What is the .1 channel?, LFE explained, Subwoofer LFE channel purpose", "rel": "What does a subwoofer do?, What is a 5.1 system?, How do I configure bass management?"},
    {"q": "What is a pre-out on an AV receiver?", "sub": "Connectivity", "sa": "A pre-out is a line-level output on an AV receiver that sends a processed, unamplified signal to an external power amplifier. This allows you to bypass the receiver's internal amplifiers for specific channels.", "a": "A pre-out (preamplifier output) is an RCA or XLR output on an AV receiver that provides a line-level, processed signal from the receiver's internal preamplifier and DSP stage — but before the internal power amplifier stage. This allows the user to connect an external power amplifier to drive one or more speaker channels. Common uses: (1) Adding a high-current external amplifier to the front left and right channels while the AVR's internal amps handle surround channels. (2) Running separate monoblock power amplifiers for maximum performance. (3) Driving a distributed zone in a multi-room audio setup. Pre-outs are typically found only on mid-range and high-end AV receivers. Budget receivers may not include pre-outs. Pre-outs carry the full signal processing including room correction applied by the receiver's DSP.", "k": "pre-out, preamp output, line level output, external amplifier connection, zone 2", "syn": "What is a pre-out on a receiver?, Can I connect an external amp to my AVR?, Pre-amp output AVR", "rel": "What is an external power amplifier?, What is a multi-zone setup?, Hi-Fi separates"},
    {"q": "What is a DAC in audio?", "sub": "Definitions", "sa": "A DAC (Digital-to-Analog Converter) converts digital audio bitstreams into analog voltage signals that can be amplified and fed to speakers. Every digital audio device contains a DAC.", "a": "A Digital-to-Analog Converter (DAC) is a semiconductor device that converts a sequence of digital binary numbers (representing audio samples) into a continuous analog voltage waveform that can be amplified by a power amplifier and converted into sound by speakers. Every device that outputs digital audio contains a DAC: smartphones, CD players, Blu-ray players, AV receivers, and computers. The quality of the DAC chip significantly affects the final sound character. Common high-quality DAC chips used in Hi-Fi equipment include the ESS Sabre series (ES9038PRO, ES9018K2M), Burr-Brown (PCM1795, PCM5102), and AKM (AK4499). A standalone external DAC is used in premium Hi-Fi systems to bypass inferior DACs built into amplifiers or streaming devices, often providing measurably lower noise floor, distortion, and better dynamic range.", "k": "DAC, digital to analog converter, audio converter, ESS sabre, burr brown, DAC chip", "syn": "What is a DAC?, Why do I need an external DAC?, Digital audio conversion", "rel": "What is a streamer?, What is Hi-Fi audio?, What is SNR?"},
    {"q": "What is an audio streamer?", "sub": "Definitions", "sa": "An audio streamer is a network-connected device that receives digital music from the internet or local network and outputs it to an amplifier or DAC. Examples include Bluesound Node, Cambridge Audio CXN, and Yamaha MusicCast devices.", "a": "An audio streamer (also called a network player) is a device designed to access digital audio content from internet streaming services (Tidal, Spotify, Qobuz, Apple Music), local network-attached storage (NAS), or DLNA/UPnP servers, and output the audio to an amplifier, AV receiver, or external DAC for playback. Key features to consider: (1) Supported streaming services and whether Tidal Connect or Roon Ready support is included. (2) DAC quality — many streamers include a built-in DAC; others output purely digital (coaxial, optical, USB) for use with an external DAC. (3) High-resolution support — whether the streamer can decode 24-bit/192kHz PCM, MQA, or DSD files. (4) Network protocols — whether it supports AirPlay 2, Chromecast, Bluetooth, or Ethernet for reliable connection. Popular streamers include Bluesound Node, Cambridge Audio CXNv2, NAD C 658, and Yamaha CD-NT670.", "k": "audio streamer, network player, Bluesound, spotify connect, Tidal, hi-fi streaming, network audio", "syn": "What is a music streamer?, Network audio player explained, Best audio streamer", "rel": "What is a DAC?, What is Hi-Fi audio?, Turntable vs streamer"},
    {"q": "What causes a ground loop hum in an audio system?", "sub": "Troubleshooting", "sa": "A ground loop hum occurs when two or more components in a system share different ground potentials, creating a low-frequency electrical current that induces an audible hum through the speakers.", "a": "A ground loop is an unwanted electrical circuit formed when two or more audio components in a system are connected to the mains earth at different points, resulting in a voltage difference between their ground connections. This differential voltage drives a small current through the audio signal cables, typically at 50Hz (mains frequency in India and the UK) or 100Hz, producing an audible hum or buzz through the speakers. Common causes: (1) Cable television or satellite receiver connected with a coaxial cable that shares a different earth reference. (2) Computer connected to the audio system via USB or analog cable. (3) Multiple components on different wall sockets with different earth impedances. Solutions include: ground loop isolators inserted in the signal path, ensuring all components share one power strip with a single earth point, lifting the earth on a non-safety-critical device, or using balanced XLR connections which are inherently immune to ground loops.", "k": "ground loop, 50Hz hum, electrical hum, buzz in speakers, mains hum, earth loop", "syn": "Why is there a hum from my speakers?, 50Hz buzz explained, How to fix ground loop", "rel": "What is balanced audio?, Why does my amplifier hiss?, Speaker distortion causes"},
    {"q": "What is balanced audio (XLR)?", "sub": "Connectivity", "sa": "Balanced audio transmits a signal on two conductors with opposite polarity signals, plus a ground. At the destination, noise induced equally on both conductors is cancelled mathematically, producing a clean signal.", "a": "Balanced audio is a method of transmitting audio signals over cable runs using two signal conductors (carrying identical but phase-inverted copies of the signal) plus a ground conductor. XLR connectors (with 3 pins: ground, hot/+, cold/-) are the standard interface for balanced connections in professional and high-end consumer audio. The balanced receiver at the destination performs common-mode rejection: it subtracts the two signals from each other. Since noise picked up along the cable is identical (common-mode) on both conductors, it cancels out perfectly when subtracted. The intentional audio signal, being opposite in polarity on the two conductors, adds together and is reinforced. Benefits of balanced audio: immunity to ground loops, immunity to electromagnetic interference over long cable runs (essential in commercial installations), and a 6dB gain in signal level. TRS (Tip-Ring-Sleeve) connectors can also carry balanced signals on shorter runs.", "k": "balanced audio, XLR, balanced connection, ground loop immunity, common mode rejection, TRS", "syn": "What is XLR audio?, Balanced vs unbalanced explained, Why use balanced cables?", "rel": "What causes a ground loop hum?, What is a preamplifier?, Professional audio connections"},
    {"q": "What is room acoustics and why does it matter?", "sub": "Acoustics", "sa": "Room acoustics refers to how sound waves behave within a room after leaving the speakers. Reflections, standing waves, and absorption all colour the sound before it reaches your ears.", "a": "When sound leaves a speaker, it does not travel directly to your ears in isolation. It reflects off walls, floors, ceilings, and furniture, arriving at your listening position at different times and from different angles. This causes several acoustic problems: (1) Early reflections — sound arriving slightly after the direct wave from side walls, floor, and ceiling, which smears stereo imaging and degrades clarity. (2) Standing waves (room modes) — at low frequencies, room dimensions cause certain bass frequencies to be exaggerated or cancelled at specific positions, producing uneven bass response. A 4m room will have a room mode at approximately 42Hz. (3) Reverberation time (RT60) — excessive reverberation in hard-surfaced rooms reduces speech intelligibility and muddies sound. Management involves a combination of acoustic absorption panels, diffusers, bass traps in corners, careful speaker placement, and digital room correction (Audyssey, Dirac Live) to address electronic resonances.", "k": "room acoustics, standing waves, room modes, reflections, bass traps, acoustic treatment", "syn": "What is room acoustics?, Why does my room make bass sound boomy?, How to improve sound in a room", "rel": "What is Audyssey calibration?, What is room correction?, How to position speakers in a room?"},
    {"q": "What is a power conditioner?", "sub": "Power Quality", "sa": "A power conditioner filters mains electrical noise, regulates voltage, and provides surge protection. It ensures audio and video equipment operates from a clean, stable power source.", "a": "A power conditioner is a mains power device designed to: (1) Filter electromagnetic interference (EMI) and radio frequency interference (RFI) from the mains supply, which can introduce noise into sensitive analog audio circuits. (2) Regulate voltage — in areas with unstable mains voltage, a conditioner with voltage regulation prevents equipment damage from under-voltage or over-voltage conditions. (3) Provide surge protection — transient voltage spikes caused by lightning strikes or grid switching events can damage or destroy audio equipment. (4) Provide isolation — some conditioners use isolation transformers to completely isolate the equipment ground from the mains earth, eliminating ground loop hum. In India, where mains power quality varies significantly between locations, a quality power conditioner is strongly recommended for high-value AV and Hi-Fi equipment. AV racks should always be on dedicated mains sockets rather than shared with appliances.", "k": "power conditioner, mains conditioner, EMI filter, surge protection, power quality, voltage regulator", "syn": "What is a mains conditioner?, Do I need a power conditioner?, Surge protector vs power conditioner", "rel": "What causes a ground loop hum?, Preventive maintenance for AV equipment, Why does my amplifier hum?"},
]
